import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.Bix3-HpO.js";const c=JSON.parse('{"title":"Page Templates","description":"Akurai Page Templates","frontmatter":{"title":"Page Templates","description":"Akurai Page Templates","weight":70,"extra":{"order":70},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai/page-templates"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai/page-templates"}],["meta",{"property":"og:title","content":"Page Templates"}],["meta",{"property":"og:description","content":"Akurai Page Templates"}],["meta",{"name":"twitter:title","content":"Page Templates"}],["meta",{"name":"twitter:description","content":"Akurai Page Templates"}]]},"headers":[],"relativePath":"docs/akurai/page-templates.md","filePath":"docs/akurai/page-templates.md"}'),l={name:"docs/akurai/page-templates.md"};function n(i,e,s,p,h,m){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="page-templates" tabindex="-1">Page Templates <a class="header-anchor" href="#page-templates" aria-label="Permalink to &quot;Page Templates&quot;">​</a></h1><p>You can define different templates for your pages in Akurai.</p><hr><h2 id="using-page-templates" tabindex="-1">Using Page Templates <a class="header-anchor" href="#using-page-templates" aria-label="Permalink to &quot;Using Page Templates&quot;">​</a></h2><p>There are 6 page templates available for displaying <strong>Pages</strong> in your website.</p><ol><li>Default Template</li><li>Left Sidebar Template</li><li>Right Sidebar Template</li><li>Hero Template</li><li>Hero Full Screen Template</li><li>Banner Template</li></ol><h3 id="default-template" tabindex="-1">Default Template <a class="header-anchor" href="#default-template" aria-label="Permalink to &quot;Default Template&quot;">​</a></h3><p><strong>Default</strong> template layout has only content area covering its 100% width. There&#39;s no sidebar used.</p><p>Check out an example of a default template <a href="https://demos.dinomatic.com/atlanta/page-templates/default-template/" target="_blank" rel="noreferrer">here</a>.</p><h3 id="left-sidebar-template" tabindex="-1">Left Sidebar Template <a class="header-anchor" href="#left-sidebar-template" aria-label="Permalink to &quot;Left Sidebar Template&quot;">​</a></h3><p><strong>Left Sidebar</strong> template layout has the content area on the right and the sidebar on the left. The sidebar used in Left Sidebar templates is called <strong>Left Sidebar</strong>.</p><p>Check out an example of a left sidebar template <a href="https://demos.dinomatic.com/atlanta/page-templates/page-with-left-sidebar/" target="_blank" rel="noreferrer">here</a>.</p><h3 id="right-sidebar-template" tabindex="-1">Right Sidebar Template <a class="header-anchor" href="#right-sidebar-template" aria-label="Permalink to &quot;Right Sidebar Template&quot;">​</a></h3><p><strong>Right Sidebar Template</strong> template layout has the content area on the left and the sidebar on the right. The sidebar used in default templates is called <strong>Main Sidebar</strong>.</p><p>Check out an example of a right sidebar template <a href="https://demos.dinomatic.com/atlanta/page-templates/page-with-right-sidebar/" target="_blank" rel="noreferrer">here</a>.</p><h3 id="page-with-top-listing" tabindex="-1">Page with Top Listing <a class="header-anchor" href="#page-with-top-listing" aria-label="Permalink to &quot;Page with Top Listing&quot;">​</a></h3><p>For general templates (Default, Left and Right Sidebar) you can add a top listing at the top of the pages. The listing has the main table design of the theme and occupies a full content width regardless whether there&#39;s a sidebar or not.</p><p>Check out an example of a page with top listing <a href="https://demos.dinomatic.com/atlanta/page-templates/page-with-top-listing/" target="_blank" rel="noreferrer">here</a>.</p><h3 id="hero-template" tabindex="-1">Hero Template <a class="header-anchor" href="#hero-template" aria-label="Permalink to &quot;Hero Template&quot;">​</a></h3><p><strong>Hero</strong> template uses the same layout as the default template, however it adds nice hero section on top of the page.</p><p>In each hero template there are 3 areas: top and main. The top area can have a heading, some text content, as well as a link/button. Top area is optional.</p><p>The main area can be either &quot;3 Reviews Block&quot; or &quot;2 Columns Block&quot;. If you choose the &quot;3 Reviews Block&quot;, you need to select reviews and they will be displayed in a grid layout.</p><p>If you choose the &quot;2 Columns Block&quot;, you&#39;ll have 2 blocks (left and right) to fill in with information. Each one of them can have either a review, a text content, a collection of links/buttons or an image. Each section can also have an optional heading.</p><p>With all these options you can have very many different page layouts, and obviously you can adjust the hero styles, e.g. background image, colors, sizes, spacing, etc.</p><p>Check out an example of a hero template <a href="https://demos.dinomatic.com/atlanta/page-templates/hero-template/" target="_blank" rel="noreferrer">here</a>.</p><h3 id="hero-full-screen-template" tabindex="-1">Hero Full Screen Template <a class="header-anchor" href="#hero-full-screen-template" aria-label="Permalink to &quot;Hero Full Screen Template&quot;">​</a></h3><p><strong>Hero Full Screen</strong> template uses the same layout as the default template, however it adds nice hero section on top of the page that covers the whole screen.</p><p>Each full screen hero template consists of 2 sections: top and bottom. Top section can have a heading and some text content, as well as a link/button. Only text content is required.</p><p>The bottom section can be either &quot;4 Columns of Review Boxes&quot; or &quot;4 Columns of Custom Content&quot;. For review boxes you just select 4 reviews and they will be displayed nicely in a grid layout. For custom content, for each box you can add an image, a heading, text content and a URL, heading and URL fields are optional.</p><p>You can adjust the hero styles, e.g. background image, colors, sizes, spacing, etc.</p><p>Check out an example of a full screen hero template <a href="https://demos.dinomatic.com/atlanta/page-templates/full-screen-hero-template/" target="_blank" rel="noreferrer">here</a>.</p><h3 id="banner-template" tabindex="-1">Banner Template <a class="header-anchor" href="#banner-template" aria-label="Permalink to &quot;Banner Template&quot;">​</a></h3><p><strong>Banner Template</strong> again uses the default page layout and adds a nice banner-like section on top. The section is divided into 3 areas: left, right and bottom.</p><p>The left area has an image background with a heading, text content and a link/button, the right area is a collection of reviews and the bottom area is some text content. You can adjust the styles for the whole section choosing all its colors and sizes.</p><p>Check out an example of a banner template <a href="https://demos.dinomatic.com/atlanta/page-templates/banner-template/" target="_blank" rel="noreferrer">here</a>.</p>',35)])])}const g=a(l,[["render",n]]);export{c as __pageData,g as default};
